import{_ as s,c as a,a as e,o as t}from"./app-B8KmK2et.js";const o="/assets/core-objects-C4gUuXAJ.png",p={};function c(l,n){return t(),a("div",null,n[0]||(n[0]=[e('<p>参考资料:</p><ul><li><a href="https://docs.microsoft.com/en-us/aspnet/core/fundamentals/logging/?view=aspnetcore-2.1&amp;tabs=aspnetcore2x" target="_blank" rel="noopener noreferrer">Logging in ASP.NET Core</a></li><li><a href="https://docs.microsoft.com/en-us/aspnet/core/fundamentals/logging/loggermessage?view=aspnetcore-2.1" target="_blank" rel="noopener noreferrer">Logging with Logger Message</a></li><li><a href="http://www.cnblogs.com/artech/p/logging-for-net-core-01.html" target="_blank" rel="noopener noreferrer">.NET Core 的日志</a></li></ul><p>本文大纲:</p><ul><li><a href="#%E5%89%8D%E8%A8%80">前言</a></li><li><a href="#%E6%97%A5%E5%BF%97%E6%A8%A1%E5%9E%8B%E4%B8%89%E8%A6%81%E7%B4%A0">日志模型三要素</a></li><li><a href="#%E5%88%9B%E5%BB%BA-logger">创建 Logger</a></li><li><a href="#%E9%87%87%E7%94%A8%E4%BE%9D%E8%B5%96%E6%B3%A8%E5%85%A5%E6%9D%A5%E5%88%9B%E5%BB%BA%E6%97%A5%E5%BF%97">采用依赖注入来创建日志</a></li><li><a href="#%E6%97%A5%E5%BF%97%E7%B1%BB%E5%88%ABcategory">日志类别(Category)</a></li><li><a href="#%E6%97%A5%E5%BF%97%E7%BA%A7%E5%88%ABloglevel">日志级别(LogLevel)</a></li><li><a href="#%E6%97%A5%E5%BF%97%E4%BA%8B%E4%BB%B6-ideventid">日志事件 ID(EventId)</a></li><li><a href="#%E6%97%A5%E5%BF%97%E6%B6%88%E6%81%AF%E6%A8%A1%E6%9D%BFmessage-template">日志消息模板(Message Template)</a></li><li><a href="#%E6%97%A5%E5%BF%97%E8%BF%87%E6%BB%A4">日志过滤</a><ul><li><a href="#%E9%80%9A%E8%BF%87%E9%85%8D%E7%BD%AE%E5%88%9B%E5%BB%BA%E6%97%A5%E5%BF%97%E8%BF%87%E6%BB%A4%E8%A7%84%E5%88%99">通过配置创建日志过滤规则</a></li><li><a href="#%E4%BB%A5%E7%BC%96%E7%A8%8B%E6%96%B9%E5%BC%8F%E5%88%9B%E5%BB%BA%E6%97%A5%E5%BF%97%E8%BF%87%E6%BB%A4%E8%A7%84%E5%88%99">以编程方式创建日志过滤规则</a></li><li><a href="#%E6%97%A5%E5%BF%97%E8%BF%87%E6%BB%A4%E8%A7%84%E5%8C%B9%E9%85%8D%E7%AE%97%E6%B3%95">日志过滤规匹配算法</a></li><li><a href="#%E6%97%A5%E5%BF%97%E6%8F%90%E4%BE%9B%E5%99%A8%E5%88%AB%E5%90%8D">日志提供器别名</a></li><li><a href="#%E9%BB%98%E8%AE%A4%E6%9C%80%E5%B0%8F%E6%97%A5%E5%BF%97%E7%BA%A7%E5%88%AB">默认最小日志级别</a></li><li><a href="#%E6%97%A5%E5%BF%97%E5%85%A8%E5%B1%80%E8%BF%87%E6%BB%A4%E5%99%A8%E5%A7%94%E6%89%98">日志全局过滤器委托</a></li></ul></li><li><a href="#%E6%97%A5%E5%BF%97%E5%8C%BA%E9%99%90log-scopes">日志区限(Log Scopes)</a></li><li><a href="#%E5%86%85%E7%BD%AE%E6%97%A5%E5%BF%97%E6%8F%90%E4%BE%9B%E5%99%A8">内置日志提供器</a><ul><li><a href="#console-%E6%8F%90%E4%BE%9B%E5%99%A8">Console 提供器</a></li><li><a href="#debug-%E6%8F%90%E4%BE%9B%E5%99%A8">Debug 提供器</a></li><li><a href="#eventsource-%E6%8F%90%E4%BE%9B%E5%99%A8">EventSource 提供器</a></li><li><a href="#windows-eventlog-%E6%8F%90%E4%BE%9B%E5%99%A8">Windows EventLog 提供器</a></li><li><a href="#tracesource-%E6%8F%90%E4%BE%9B%E5%99%A8">TraceSource 提供器</a></li><li><a href="#azure-app-service-%E6%8F%90%E4%BE%9B%E5%99%A8">Azure App Service 提供器</a></li></ul></li><li><a href="#loggermessage-%E6%A8%A1%E5%BC%8F">LoggerMessage 模式</a><ul><li><a href="#loggermessagedefine">LoggerMessage.Define</a></li><li><a href="#loggermessagedefinescope">LoggerMessage.DefineScope</a></li></ul></li></ul><h1 id="前言" tabindex="-1"><a class="header-anchor" href="#前言"><span>前言</span></a></h1><p>.NET Core提供了独立的日志模型使我们可以采用统一的 API 来完成针对日志记录的编程，我们同时也可以利用其扩展点对这个模型进行定制，比如可以将第三方日志提供器整合到我们的应用中。</p><h1 id="日志模型三要素" tabindex="-1"><a class="header-anchor" href="#日志模型三要素"><span>日志模型三要素</span></a></h1><p>日志记录编程的核心对象:</p><ul><li>ILogger: 将日志消息写到对应的目的地(如文件，数据库等)</li><li>ILoggerFactory: 创建组合式的 Logger，该 Logger 其实是对一组 Logger 的封装，自身并不提供日志写入功能，而是委托内部封装的 Logger 来写日志。</li><li>ILoggerProvider: 创建具有写入日志功能的 Logger。</li></ul><p>LoggerFactory 可以注册多个 LoggerProvider 对象，在进行日志编程时，我们会利用 LoggerFactory 对象创建 Logger 来写日志，而该对象委托的内部 Logger 则由这些 LoggerProvider 提供。这三者的关系如下:</p><p><img src="'+o+`" alt="三个核心对象之间的关系"></p><h1 id="创建-logger" tabindex="-1"><a class="header-anchor" href="#创建-logger"><span>创建 Logger</span></a></h1><p>引入以下 Nuget Package 以实现原始的日志功能:</p><ul><li>Microsoft.Extensions.Logging.Abstractions: 引入 <code>ILoggerFactory</code> 和 <code>ILogger</code> 接口</li><li>Microsoft.Extensions.Logging: 引入 <code>ILoggerFactory</code> 的默认实现 <code>LoggerFactory</code></li><li>Microsoft.Extensions.Logging.Console: 引入 <code>ConsoleLoggerProvider</code></li><li>Microsoft.Extensions.Logging.Debug: 引入 <code>DebugLoggerProvider</code></li><li>System.Text.Encoding.CodePages: 由于 .NET Core 在默认情况下并不支持中文编码，需要在程序启动的时候显式注册一个支持中文编码的 <code>EncodingProvider</code></li></ul><p>首先创建 <code>LoggerFactory</code> 对象，然后通过 <code>AddProvider</code> 方法将一个 <code>ConsoleLoggerProvider</code> 和 <code>DebugLoggerProvider</code> 对象注册到 <code>LoggerFactory</code> 上，这两个 <code>LoggerProvider</code> 的构造函数接收一个 <code>Func&lt;string, LogLevel, bool&gt;</code> 类型的参数，该委托对象的两个输入参数分别代表日志消息的类型和等级，布尔类型的返回值决定创建的 <code>Logger</code> 是否会写入给定的日志消息。由于传入的委托对象总是返回 True，意味着所有级别的日志消息均会被这两个 <code>LoggerProvider</code> 创建的 <code>Logger</code> 对象写入对应的目的地。日志提供器注册完成之后，调用 <code>LoggerFactory</code> 的 <code>CreateLogger</code> 方法创建一个指定类别的 <code>Logger</code> 对象。</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">class</span> <span class="token class-name">Program</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">Main</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span></span> args<span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            <span class="token comment">// 注册 EncodingProvider 实现对中文编码的支持</span></span>
<span class="line">            Encoding<span class="token punctuation">.</span><span class="token function">RegisterProvider</span><span class="token punctuation">(</span>CodePagesEncodingProvider<span class="token punctuation">.</span>Instance<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">            <span class="token class-name">Func<span class="token punctuation">&lt;</span><span class="token keyword">string</span><span class="token punctuation">,</span> LogLevel<span class="token punctuation">,</span> <span class="token keyword">bool</span><span class="token punctuation">&gt;</span></span> filter <span class="token operator">=</span> <span class="token punctuation">(</span>category<span class="token punctuation">,</span> level<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token class-name">ILoggerFactory</span> loggerFactory <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">LoggerFactory</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            loggerFactory<span class="token punctuation">.</span><span class="token function">AddProvider</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token constructor-invocation class-name">ConsoleLoggerProvider</span><span class="token punctuation">(</span>filter<span class="token punctuation">,</span> <span class="token boolean">false</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            loggerFactory<span class="token punctuation">.</span><span class="token function">AddProvider</span><span class="token punctuation">(</span><span class="token keyword">new</span> <span class="token constructor-invocation class-name">DebugLoggerProvider</span><span class="token punctuation">(</span>filter<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token class-name">ILogger</span> logger <span class="token operator">=</span> loggerFactory<span class="token punctuation">.</span><span class="token function">CreateLogger</span><span class="token punctuation">(</span><span class="token keyword">nameof</span><span class="token punctuation">(</span>Program<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">            <span class="token class-name"><span class="token keyword">int</span></span> eventId <span class="token operator">=</span> <span class="token number">3721</span><span class="token punctuation">;</span></span>
<span class="line">            logger<span class="token punctuation">.</span><span class="token function">LogInformation</span><span class="token punctuation">(</span>eventId<span class="token punctuation">,</span> <span class="token interpolation-string"><span class="token string">$&quot;升级到 .NET Core version 1.0.0&quot;</span></span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            logger<span class="token punctuation">.</span><span class="token function">LogWarning</span><span class="token punctuation">(</span>eventId<span class="token punctuation">,</span> <span class="token string">&quot;并发量接近上限&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            logger<span class="token punctuation">.</span><span class="token function">LogError</span><span class="token punctuation">(</span>eventId<span class="token punctuation">,</span> <span class="token string">&quot;数据库连接失败(数据库：{Database}，用户名：{User})&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;TestDb&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;sa&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="采用依赖注入来创建日志" tabindex="-1"><a class="header-anchor" href="#采用依赖注入来创建日志"><span>采用依赖注入来创建日志</span></a></h1><p>在 ASP.NET Core 应用中，总是以依赖注入的方式来获取相关的服务类型实例，<code>ILoggerFactory</code> 就是服务类型的一种。在创建 <code>ServiceCollection</code> 对象之后，调用 <code>AddLogging()</code> 向其注册日志服务，再从 <code>ServiceCollection</code> 对象中获取 <code>ILoggerFactory</code> 对象，调用 <code>ILoggerFactory</code> 的 <code>AddConsole()</code> 和 <code>AddDebug()</code> 扩展方法完成日志提供器向 <code>ILoggerFactory</code> 的注册。</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token class-name"><span class="token keyword">var</span></span> logger <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">ServiceCollection</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">                <span class="token punctuation">.</span><span class="token function">AddLogging</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// call this extension method to register logging service</span></span>
<span class="line">                <span class="token punctuation">.</span><span class="token function">BuildServiceProvider</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// build service provider to get services</span></span>
<span class="line">                <span class="token punctuation">.</span><span class="token generic-method"><span class="token function">GetService</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>ILoggerFactory<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// get ILoggerFactory service</span></span>
<span class="line">                <span class="token punctuation">.</span><span class="token function">AddConsole</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// register console logger provider to logger factory</span></span>
<span class="line">                <span class="token punctuation">.</span><span class="token function">AddDebug</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// register debug logger provider to logger factory</span></span>
<span class="line">                <span class="token punctuation">.</span><span class="token function">CreateLogger</span><span class="token punctuation">(</span><span class="token keyword">nameof</span><span class="token punctuation">(</span>Program<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// create logger of category &#39;Program&#39;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同一个 <code>LoggerFactory</code> 可以注册多个 <code>LoggerProvider，当</code> <code>LoggerFactory</code> 创建出相应的 <code>Logger</code> 对象来写入日志时，日志消息实际上会分发给所有 <code>LoggerProvider</code>。而每条日志消息都携带了日志等级， <code>LoggerProvider</code> 通过其构造函数传入的 Func 委托来过滤不同等级的日志消息，这样就实现了一条日志消息只写入特定的日志提供器的目的地。</p><h1 id="日志类别-category" tabindex="-1"><a class="header-anchor" href="#日志类别-category"><span>日志类别(Category)</span></a></h1><p>每一条日志消息都带有日志类别信息，在创建 ILogger 时可以指定类别，类别为任何字符串值，但按照惯例日志类别为类型的完全限定名，例如: &quot;TodoApi.Controllers.TodoController&quot;。</p><p>调用 <code>ILoggerFactory.CreateLogger</code> 时可以指定日志类别:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">TodoController</span> <span class="token punctuation">:</span> <span class="token type-list"><span class="token class-name">Controller</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">readonly</span> <span class="token class-name">ITodoRepository</span> _todoRepository<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">readonly</span> <span class="token class-name">ILogger</span> _logger<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token function">TodoController</span><span class="token punctuation">(</span><span class="token class-name">ITodoRepository</span> todoRepository<span class="token punctuation">,</span></span>
<span class="line">        <span class="token class-name">ILoggerFactory</span> logger<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        _todoRepository <span class="token operator">=</span> todoRepository<span class="token punctuation">;</span></span>
<span class="line">        _logger <span class="token operator">=</span> logger<span class="token punctuation">.</span><span class="token function">CreateLogger</span><span class="token punctuation">(</span><span class="token string">&quot;TodoApi.Controllers.TodoController&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>更多时候使用 <code>ILogger&lt;T&gt;</code> 则更简单:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">public</span> <span class="token keyword">class</span> <span class="token class-name">TodoController</span> <span class="token punctuation">:</span> <span class="token type-list"><span class="token class-name">Controller</span></span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">readonly</span> <span class="token class-name">ITodoRepository</span> _todoRepository<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">private</span> <span class="token keyword">readonly</span> <span class="token class-name">ILogger</span> _logger<span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    <span class="token keyword">public</span> <span class="token function">TodoController</span><span class="token punctuation">(</span><span class="token class-name">ITodoRepository</span> todoRepository<span class="token punctuation">,</span></span>
<span class="line">        <span class="token class-name">ILogger<span class="token punctuation">&lt;</span>TodoController<span class="token punctuation">&gt;</span></span> logger<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        _todoRepository <span class="token operator">=</span> todoRepository<span class="token punctuation">;</span></span>
<span class="line">        _logger <span class="token operator">=</span> logger<span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="日志级别-loglevel" tabindex="-1"><a class="header-anchor" href="#日志级别-loglevel"><span>日志级别(LogLevel)</span></a></h1><p>日志级别由轻至重分别为:</p><ul><li>Trace = 0: 提供给发开人员用于跟踪和调试的信息，通常包含一些敏感数据，绝不能暴露给用户</li><li>Debug = 1: 在开发与调试阶段帮助开发人员分析调试的信息，这些消息通常是短期有效的信息，在部署环境中不会启用该级别</li><li>Information = 2: 记录应用程序的正常行为的日志级别，这些消息通常具有长期有效性。</li><li>Warning = 3: 记录应用程序运行期间不正常或意外事件的日志，这些行为不会导致应用程序崩溃但需要记录下来以供后续调查。</li><li>Error = 4: 记录无法被处理的错误及异常，这些消息指示在单一事务边界内失败，但不影响应用程序的其他部分</li><li>Critical = 5: 记录需要立即进行修正的致命错误，最高警戒级别</li></ul><p>ASP.NET Core 将框架级别的事件日志以 Debug 级别日志分发给不同的日志提供器。</p><h1 id="日志事件-id-eventid" tabindex="-1"><a class="header-anchor" href="#日志事件-id-eventid"><span>日志事件 ID(EventId)</span></a></h1><p>每记录一条日志，都可以为其指定事件 ID，事件 ID 用于将一系列相互关联的日志消息串起来，例如，将某件产品添加至购物车相关的日志的 ID 可为 1000，而与结账付款的事件 ID 可为 1001。日志事件 ID 以数据的形式将不同的日志进行逻辑分组，方便日后的查阅与分析。</p><h1 id="日志消息模板-message-template" tabindex="-1"><a class="header-anchor" href="#日志消息模板-message-template"><span>日志消息模板(Message Template)</span></a></h1><p>在调用 ILogger.Log() 时，需要为每条日志消息提供消息模板，该消息模板不同于传统 C# 格式化字符串和最新的插值字符串，其中包含命名占位符而不是数字占位符，填充到占位符的顺序又不与其名称相对应，而是按照占位符的顺序，日志框架这样设计是为了让日志提供器能够实现语义化或结构化的日志存储。如果采用以下方式写入日志:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token class-name"><span class="token keyword">string</span></span> p1 <span class="token operator">=</span> <span class="token string">&quot;parm1&quot;</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token class-name"><span class="token keyword">string</span></span> p2 <span class="token operator">=</span> <span class="token string">&quot;parm2&quot;</span><span class="token punctuation">;</span></span>
<span class="line">_logger<span class="token punctuation">.</span><span class="token function">LogInformation</span><span class="token punctuation">(</span><span class="token string">&quot;Parameter values: {p2}, {p1}&quot;</span><span class="token punctuation">,</span> p1<span class="token punctuation">,</span> p2<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>将会得到的输出结果为:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">Parameter values: parm1, parm2</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><blockquote><p>按照笔者的理解，许多日志提供器都采用了将占位符参数以字段的形式进行存储的功能，在消息模板中的占位符既是可以在消息输出中被替代的字符串，也是在结构化存储中的字段信息，当收集到大量的日志数据之后，通过结构化查询语句将大大提供分析效率。</p></blockquote><h1 id="日志过滤" tabindex="-1"><a class="header-anchor" href="#日志过滤"><span>日志过滤</span></a></h1><p>可以针对特定的提供器，或类别，或所有提供器或所有类别指定最小记录的日志级别，小于该级别的日志消息将不会分布至相应的日志提供器，同样，可通过将日志级别设置为 <code>LogLevel.None</code> 来忽略所有日志。</p><h2 id="通过配置创建日志过滤规则" tabindex="-1"><a class="header-anchor" href="#通过配置创建日志过滤规则"><span>通过配置创建日志过滤规则</span></a></h2><p>ASP.NET Core 项目模板的代码调用 CreateDefaultBuilder 方法了，该方法默认注册了 <code>Console</code> 和 <code>Debug</code> 提供器，同时告知日志系统查询 <code>Logging</code> 配置块来加载日志配置。</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">Main</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">string</span><span class="token punctuation">[</span><span class="token punctuation">]</span></span> args<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name"><span class="token keyword">var</span></span> webHost <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">WebHostBuilder</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">UseKestrel</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">UseContentRoot</span><span class="token punctuation">(</span>Directory<span class="token punctuation">.</span><span class="token function">GetCurrentDirectory</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">ConfigureAppConfiguration</span><span class="token punctuation">(</span><span class="token punctuation">(</span>hostingContext<span class="token punctuation">,</span> config<span class="token punctuation">)</span> <span class="token operator">=&gt;</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            <span class="token class-name"><span class="token keyword">var</span></span> env <span class="token operator">=</span> hostingContext<span class="token punctuation">.</span>HostingEnvironment<span class="token punctuation">;</span></span>
<span class="line">            config<span class="token punctuation">.</span><span class="token function">AddJsonFile</span><span class="token punctuation">(</span><span class="token string">&quot;appsettings.json&quot;</span><span class="token punctuation">,</span> <span class="token named-parameter punctuation">optional</span><span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token named-parameter punctuation">reloadOnChange</span><span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">)</span></span>
<span class="line">                  <span class="token punctuation">.</span><span class="token function">AddJsonFile</span><span class="token punctuation">(</span><span class="token interpolation-string"><span class="token string">$&quot;appsettings.</span><span class="token interpolation"><span class="token punctuation">{</span><span class="token expression language-csharp">env<span class="token punctuation">.</span>EnvironmentName</span><span class="token punctuation">}</span></span><span class="token string">.json&quot;</span></span><span class="token punctuation">,</span> <span class="token named-parameter punctuation">optional</span><span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token named-parameter punctuation">reloadOnChange</span><span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            config<span class="token punctuation">.</span><span class="token function">AddEnvironmentVariables</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">ConfigureLogging</span><span class="token punctuation">(</span><span class="token punctuation">(</span>hostingContext<span class="token punctuation">,</span> logging<span class="token punctuation">)</span> <span class="token operator">=&gt;</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            logging<span class="token punctuation">.</span><span class="token function">AddConfiguration</span><span class="token punctuation">(</span>hostingContext<span class="token punctuation">.</span>Configuration<span class="token punctuation">.</span><span class="token function">GetSection</span><span class="token punctuation">(</span><span class="token string">&quot;Logging&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            logging<span class="token punctuation">.</span><span class="token function">AddConsole</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            logging<span class="token punctuation">.</span><span class="token function">AddDebug</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token generic-method"><span class="token function">UseStartup</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>Startup<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span>
<span class="line">    webHost<span class="token punctuation">.</span><span class="token function">Run</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>配置数据以日志提供器和类别为单位指定了最小日志级别，例如:</p><div class="language-JSON line-numbers-mode" data-highlighter="prismjs" data-ext="JSON"><pre><code class="language-JSON"><span class="line">{</span>
<span class="line">  &quot;Logging&quot;: {</span>
<span class="line">    &quot;IncludeScopes&quot;: false,</span>
<span class="line">    &quot;Debug&quot;: {</span>
<span class="line">      &quot;LogLevel&quot;: {</span>
<span class="line">        &quot;Default&quot;: &quot;Information&quot;</span>
<span class="line">      }</span>
<span class="line">    },</span>
<span class="line">    &quot;Console&quot;: {</span>
<span class="line">      &quot;LogLevel&quot;: {</span>
<span class="line">        &quot;Microsoft.AspNetCore.Mvc.Razor.Internal&quot;: &quot;Warning&quot;,</span>
<span class="line">        &quot;Microsoft.AspNetCore.Mvc.Razor.Razor&quot;: &quot;Debug&quot;,</span>
<span class="line">        &quot;Microsoft.AspNetCore.Mvc.Razor&quot;: &quot;Error&quot;,</span>
<span class="line">        &quot;Default&quot;: &quot;Information&quot;</span>
<span class="line">      }</span>
<span class="line">    },</span>
<span class="line">    &quot;LogLevel&quot;: {</span>
<span class="line">      &quot;Default&quot;: &quot;Debug&quot;</span>
<span class="line">    }</span>
<span class="line">  }</span>
<span class="line">}</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="以编程方式创建日志过滤规则" tabindex="-1"><a class="header-anchor" href="#以编程方式创建日志过滤规则"><span>以编程方式创建日志过滤规则</span></a></h2><p>考虑以下代码:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line">WebHost<span class="token punctuation">.</span><span class="token function">CreateDefaultBuilder</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token generic-method"><span class="token function">UseStartup</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>Startup<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">ConfigureLogging</span><span class="token punctuation">(</span>logging <span class="token operator">=&gt;</span></span>
<span class="line">        logging<span class="token punctuation">.</span><span class="token function">AddFilter</span><span class="token punctuation">(</span><span class="token string">&quot;System&quot;</span><span class="token punctuation">,</span> LogLevel<span class="token punctuation">.</span>Debug<span class="token punctuation">)</span></span>
<span class="line">               <span class="token punctuation">.</span><span class="token generic-method"><span class="token function">AddFilter</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>DebugLoggerProvider<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token string">&quot;Microsoft&quot;</span><span class="token punctuation">,</span> LogLevel<span class="token punctuation">.</span>Trace<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>第一个 <code>AddFilter</code> 方法指示所有提供器的 &quot;System&quot; 类别最小日志级别为 <code>Debug</code>。</li><li>第二个 <code>AddFilter</code> 方法指示 <code>Debug</code> 日志提供器的 &quot;Microsoft&quot; 类别最小日志级别为 <code>Trace</code>。</li></ul><h2 id="日志过滤规匹配算法" tabindex="-1"><a class="header-anchor" href="#日志过滤规匹配算法"><span>日志过滤规匹配算法</span></a></h2><p>综合以上配置项和编程方式添加的过滤规则，其可以解释为:</p><table><thead><tr><th>Number</th><th>Provider</th><th>Categories that begin with ...</th><th>Minimun log level</th></tr></thead><tbody><tr><td>1</td><td>Debug</td><td>All categories</td><td>Information</td></tr><tr><td>2</td><td>Console</td><td>Microsoft.AspNetCore.Mvc.Razor.Internal</td><td>Warning</td></tr><tr><td>3</td><td>Console</td><td>Microsoft.AspNetCore.Mvc.Razor.Razor</td><td>Debug</td></tr><tr><td>4</td><td>Console</td><td>Microsoft.AspNetCore.Mvc.Razor</td><td>Error</td></tr><tr><td>5</td><td>Console</td><td>All categories</td><td>Information</td></tr><tr><td>6</td><td>All providers</td><td>All categories</td><td>Debug</td></tr><tr><td>7</td><td>All providers</td><td>System</td><td>Debug</td></tr><tr><td>8</td><td>Debug</td><td>Microsoft</td><td>Trace</td></tr></tbody></table><p>当一个指定类别的 ILogger 对象写入日志消息时，框架尝试使用以下逻辑来匹配过滤规则:</p><ol><li>选出所有匹配提供器或其别名的规则，如果没有任何规则匹配到该提供器，则应用所有不指定提供器的规则</li><li>在从 1 中筛选出的结果的基础上，选出匹配类别的最长类别规则，如果找不到任何规则，则应用所有未指定类别的规则</li><li>如果有多个规则匹配，则选择<strong>最后</strong>一个</li><li>如果没有任何匹配的规则，则应用<a href="#%E9%BB%98%E8%AE%A4%E6%9C%80%E5%B0%8F%E6%97%A5%E5%BF%97%E7%BA%A7%E5%88%AB">默认最小日志级别</a></li></ol><p>假设现在有一个类别为 &quot;Microsoft.AspNetCore.Mvc.Razor.RazorViewEngine&quot; 的 <code>ILogger</code> 对象，当其写入日志消息时:</p><ul><li>Debug 提供器为其筛选出表格中的 1, 6, 8 规则，由于规则 8 最具体，所以规则 8 被应用</li><li>Console 提供器为其筛选出 3, 4, 5, 6 规则，规则 3 最具体，它会被应用</li></ul><p>因此，当该 <code>ILogger</code> 对象写入日志时，Debug 提供器将输出把级别 <code>Trace</code> 以上的日志消息，而 Console 提供器则输出级别 <code>Debug</code> 以上的日志消息。</p><h2 id="日志提供器别名" tabindex="-1"><a class="header-anchor" href="#日志提供器别名"><span>日志提供器别名</span></a></h2><p>在配置项中可以将提供器的类型名作为其配置项的根节点，每个日志提供器也定义了别名，.NET Core 定义了以下日志提供器的别名:</p><ul><li>Console:</li><li>Debug:</li><li>EventLog:</li><li>AzureAppServices</li><li>TraceSource</li><li>EventSource</li></ul><h2 id="默认最小日志级别" tabindex="-1"><a class="header-anchor" href="#默认最小日志级别"><span>默认最小日志级别</span></a></h2><p>前文提到，在没有任何日志过滤规则匹配时，会采用默认最小日志级别，以下代码展示了如何设置默认最小级别:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line">WebHost<span class="token punctuation">.</span><span class="token function">CreateDefaultBuilder</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token generic-method"><span class="token function">UseStartup</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>Startup<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">ConfigureLogging</span><span class="token punctuation">(</span>logging <span class="token operator">=&gt;</span> logging<span class="token punctuation">.</span><span class="token function">SetMinimumLevel</span><span class="token punctuation">(</span>LogLevel<span class="token punctuation">.</span>Warning<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>如果没有显式指定默认最小日志级别，那么框架的默认值为 <code>Information</code>。</p></blockquote><h2 id="日志全局过滤器委托" tabindex="-1"><a class="header-anchor" href="#日志全局过滤器委托"><span>日志全局过滤器委托</span></a></h2><p>可以向框架注册一个 <code>Func&lt;Provider, Category, LogLevel&gt;</code> 的委托，让匹配不到任何日志过滤规则的 <code>ILogger</code> 对象通过该委托获得日志级别:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line">WebHost<span class="token punctuation">.</span><span class="token function">CreateDefaultBuilder</span><span class="token punctuation">(</span>args<span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token generic-method"><span class="token function">UseStartup</span><span class="token generic class-name"><span class="token punctuation">&lt;</span>Startup<span class="token punctuation">&gt;</span></span></span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">ConfigureLogging</span><span class="token punctuation">(</span>logBuilder <span class="token operator">=&gt;</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        logBuilder<span class="token punctuation">.</span><span class="token function">AddFilter</span><span class="token punctuation">(</span><span class="token punctuation">(</span>provider<span class="token punctuation">,</span> category<span class="token punctuation">,</span> logLevel<span class="token punctuation">)</span> <span class="token operator">=&gt;</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            <span class="token keyword">if</span> <span class="token punctuation">(</span>provider <span class="token operator">==</span> <span class="token string">&quot;Microsoft.Extensions.Logging.Console.ConsoleLoggerProvider&quot;</span> <span class="token operator">&amp;&amp;</span> </span>
<span class="line">                category <span class="token operator">==</span> <span class="token string">&quot;TodoApi.Controllers.TodoController&quot;</span><span class="token punctuation">)</span></span>
<span class="line">            <span class="token punctuation">{</span></span>
<span class="line">                <span class="token keyword">return</span> <span class="token boolean">false</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token punctuation">}</span></span>
<span class="line">            <span class="token keyword">return</span> <span class="token boolean">true</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="日志区限-log-scopes" tabindex="-1"><a class="header-anchor" href="#日志区限-log-scopes"><span>日志区限(Log Scopes)</span></a></h1><p>可通过 <code>scope</code> 的方式将一系列由在逻辑上相互关联的操作产生的日志消息组合成一个集合，例如，你可能希望将一个数据库事务中产生的所有日志消息包含相同的事务 ID。调用 <code>ILogger.BeginScope&lt;TState&gt;</code> 返回一个 Scope 对象，该对象实现了 <code>IDisposable</code> 接口，通常使用 <code>using</code> 语句将一组与 Scope 相关的日志消息写入包围起来:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">public</span> <span class="token return-type class-name">IActionResult</span> <span class="token function">GetById</span><span class="token punctuation">(</span><span class="token class-name"><span class="token keyword">string</span></span> id<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token class-name">TodoItem</span> item<span class="token punctuation">;</span></span>
<span class="line">    <span class="token keyword">using</span> <span class="token punctuation">(</span>_logger<span class="token punctuation">.</span><span class="token function">BeginScope</span><span class="token punctuation">(</span><span class="token string">&quot;Message attached to logs created in the using block&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        _logger<span class="token punctuation">.</span><span class="token function">LogInformation</span><span class="token punctuation">(</span>LoggingEvents<span class="token punctuation">.</span>GetItem<span class="token punctuation">,</span> <span class="token string">&quot;Getting item {ID}&quot;</span><span class="token punctuation">,</span> id<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        item <span class="token operator">=</span> _todoRepository<span class="token punctuation">.</span><span class="token function">Find</span><span class="token punctuation">(</span>id<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token keyword">if</span> <span class="token punctuation">(</span>item <span class="token operator">==</span> <span class="token keyword">null</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">{</span></span>
<span class="line">            _logger<span class="token punctuation">.</span><span class="token function">LogWarning</span><span class="token punctuation">(</span>LoggingEvents<span class="token punctuation">.</span>GetItemNotFound<span class="token punctuation">,</span> <span class="token string">&quot;GetById({ID}) NOT FOUND&quot;</span><span class="token punctuation">,</span> id<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">            <span class="token keyword">return</span> <span class="token function">NotFound</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token keyword">new</span> <span class="token constructor-invocation class-name">ObjectResult</span><span class="token punctuation">(</span>item<span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以下代码在 Program.cs 中为 Console 提供器启用了日志区限:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token punctuation">.</span><span class="token function">ConfigureLogging</span><span class="token punctuation">(</span><span class="token punctuation">(</span>hostingContext<span class="token punctuation">,</span> logging<span class="token punctuation">)</span> <span class="token operator">=&gt;</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    logging<span class="token punctuation">.</span><span class="token function">AddConfiguration</span><span class="token punctuation">(</span>hostingContext<span class="token punctuation">.</span>Configuration<span class="token punctuation">.</span><span class="token function">GetSection</span><span class="token punctuation">(</span><span class="token string">&quot;Logging&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    logging<span class="token punctuation">.</span><span class="token function">AddConsole</span><span class="token punctuation">(</span>options <span class="token operator">=&gt;</span> options<span class="token punctuation">.</span>IncludeScopes <span class="token operator">=</span> <span class="token boolean">true</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    logging<span class="token punctuation">.</span><span class="token function">AddDebug</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><blockquote><p>在 <code>appsetings</code> 配置文件中使用配置项启用该功能仅在 ASP.NET Core 2.1 版本以后可用</p></blockquote><p>这样，每条日志消息都会包含完整的区限信息:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">info: TodoApi.Controllers.TodoController[1002]</span>
<span class="line">      =&gt; RequestId:0HKV9C49II9CK RequestPath:/api/todo/0 =&gt; TodoApi.Controllers.TodoController.GetById (TodoApi) =&gt; Message attached to logs created in the using block</span>
<span class="line">      Getting item 0</span>
<span class="line">warn: TodoApi.Controllers.TodoController[4000]</span>
<span class="line">      =&gt; RequestId:0HKV9C49II9CK RequestPath:/api/todo/0 =&gt; TodoApi.Controllers.TodoController.GetById (TodoApi) =&gt; Message attached to logs created in the using block</span>
<span class="line">      GetById(0) NOT FOUND</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="内置日志提供器" tabindex="-1"><a class="header-anchor" href="#内置日志提供器"><span>内置日志提供器</span></a></h1><p>ASP.NET Core 内置了以下提供器:</p><ul><li>Console</li><li>Debug</li><li>EventLog</li><li>AzureAppServices</li><li>TraceSource</li><li>EventSource</li></ul><h2 id="console-提供器" tabindex="-1"><a class="header-anchor" href="#console-提供器"><span>Console 提供器</span></a></h2><p>Microsoft.Extensions.Logging.Console 包将日志消息输出到控制台:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">logging.AddConsole()</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="debug-提供器" tabindex="-1"><a class="header-anchor" href="#debug-提供器"><span>Debug 提供器</span></a></h2><p>Microsoft.Extensions.Logging.Debug 包通过 System.Diagnostics.Debug 类(调用 Debug.WriteLine 方法)输出日志消息，在 Linux 系统中，该提供器将日志写入 <code>/var/log/message</code> 中。</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">logging.AddDebug()</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="eventsource-提供器" tabindex="-1"><a class="header-anchor" href="#eventsource-提供器"><span>EventSource 提供器</span></a></h2><p>Microsoft.Extensions.Logging.EventSource 包实现了事件追踪，在 Windows 系统下，它使用 ETW，该提供器是跨平台的，但在 Linux 或 macOS 下尚无可用的可视化工具。</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">logging.AddEventSourceLogger()</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="windows-eventlog-提供器" tabindex="-1"><a class="header-anchor" href="#windows-eventlog-提供器"><span>Windows EventLog 提供器</span></a></h2><p>Microsoft.Extensions.Logging.EventLog 包将日志发送至 Windows Event Log。</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">logging.AddEventLog()</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="tracesource-提供器" tabindex="-1"><a class="header-anchor" href="#tracesource-提供器"><span>TraceSource 提供器</span></a></h2><p>Microsoft.Extensions.Logging.TraceSource 包利用 System.Diagnostics.TraceSource 库和提供器。</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">logging.AddTraceSource(sourceSwitchName)</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><blockquote><p>该提供当前仅支持 .NET Framework 版本。</p></blockquote><h2 id="azure-app-service-提供器" tabindex="-1"><a class="header-anchor" href="#azure-app-service-提供器"><span>Azure App Service 提供器</span></a></h2><p>Microsoft.Extensions.Logging.AzureAppServices 包将日志写入到 Azure App Service 应用的文件系统的文本文件和 Azure Storage 帐号的 <a href="https://docs.microsoft.com/en-us/azure/storage/blobs/storage-quickstart-blobs-dotnet?tabs=windows#what-is-blob-storage" target="_blank" rel="noopener noreferrer">blob storage</a>，该提供器仅在 ASP.NET Core 1.1 版本以后可用。</p><h1 id="loggermessage-模式" tabindex="-1"><a class="header-anchor" href="#loggermessage-模式"><span>LoggerMessage 模式</span></a></h1><p>与日志系统的扩展方法模式相比，<code>LoggerMessage</code> 模式可减少对象的分配和计算量以提供性能。该模式提供了以下优点:</p><ul><li>扩展方法模式，如 <code>LogInformation</code>, <code>LogDebug</code> 和 <code>LogError</code> 等方法会装箱值对象，而 <code>LoggerMessage</code> 模式通过使用强类型参数的 <code>Action</code> 委托避免了装箱</li><li>扩展方法模式在每条日志消息写入时都要求传递消息模板，而 <code>LoggerMessage</code> 模式仅在消息定义时传递消息模板</li></ul><h2 id="loggermessage-define" tabindex="-1"><a class="header-anchor" href="#loggermessage-define"><span>LoggerMessage.Define</span></a></h2><p><code>LoggerMessage.Define</code> 的示例代码可参考<a href="https://github.com/aspnet/Docs/tree/master/aspnetcore/fundamentals/logging/loggermessage/sample/" target="_blank" rel="noopener noreferrer">示例代码</a></p><p><code>LoggerMessage.Define</code> 静态方法创建并返回一个 <code>Action</code> 委托用以记录日志，其重载最高支持 6 个消息模板的命名参数，传递至 Define 方法的字符串是一个包含变量占位符的消息模板而不是一个插值字符串(形如 <code>This is a {variable}.</code>)，占位符以定义的参数顺序依次被填充</p><blockquote><p>占位符的名称应该在多个消息模板之间保持一致，它们在结构化存储中扮演了字段名的角色，推荐以 Pascal 风格来命名占位符，例如 <code>{Count}</code>, <code>{FirstName}</code>。</p></blockquote><p>每条日志记录方法都是一个由 <code>LoggerMessage.Define</code> 方法创建的 <code>Action</code> 委托，例如:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">private</span> <span class="token keyword">static</span> <span class="token keyword">readonly</span> <span class="token class-name">Action<span class="token punctuation">&lt;</span>ILogger<span class="token punctuation">,</span> Exception<span class="token punctuation">&gt;</span></span> _indexPageRequested<span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>对于该 Action，指定:</p><ul><li>日志级别</li><li>一个唯一的事件 ID(EventId)和包含扩展方法的类型的名称</li><li>消息模板</li></ul><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line">_indexPageRequested <span class="token operator">=</span> LoggerMessage<span class="token punctuation">.</span><span class="token function">Define</span><span class="token punctuation">(</span></span>
<span class="line">    LogLevel<span class="token punctuation">.</span>Information<span class="token punctuation">,</span> </span>
<span class="line">    <span class="token keyword">new</span> <span class="token constructor-invocation class-name">EventId</span><span class="token punctuation">(</span><span class="token number">1</span><span class="token punctuation">,</span> <span class="token keyword">nameof</span><span class="token punctuation">(</span>IndexPageRequested<span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span> </span>
<span class="line">    <span class="token string">&quot;GET request for Index page&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>上述代码表示:</p><ul><li>日志级别设置为 <code>Information</code></li><li>事件 ID 设为 1 并传入 <code>IndexPageRequested</code> 类型的名称</li><li>自定义的消息模板</li></ul><p><code>Action</code> 委托由一个定义为 <code>ILogger</code> 的强类型 <code>IndexPageRequested</code> 扩展方法调用:</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">IndexPageRequested</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">ILogger</span> logger<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">_indexPageRequested</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> <span class="token keyword">null</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>ILogger</code> 在 <code>OnGetAsync</code> 方法中调用 <code>IndexPageRequested</code> 扩展方法完成日志记录。</p><div class="language-csharp line-numbers-mode" data-highlighter="prismjs" data-ext="cs"><pre><code class="language-csharp"><span class="line"><span class="token keyword">public</span> <span class="token keyword">static</span> <span class="token return-type class-name"><span class="token keyword">void</span></span> <span class="token function">IndexPageRequested</span><span class="token punctuation">(</span><span class="token keyword">this</span> <span class="token class-name">ILogger</span> logger<span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">{</span></span>
<span class="line">    _logger<span class="token punctuation">.</span><span class="token function">IndexPageRequested</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">    Quotes <span class="token operator">=</span> <span class="token keyword">await</span> _db<span class="token punctuation">.</span>Quotes<span class="token punctuation">.</span><span class="token function">AsNoTracking</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">ToListAsync</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="loggermessage-definescope" tabindex="-1"><a class="header-anchor" href="#loggermessage-definescope"><span>LoggerMessage.DefineScope</span></a></h2><p><code>LoggerMessage.DefineScope</code> 遵循一样的模式，不同之处在于其返回一个 <code>Func&lt;T,IDisposable&gt;</code> 委托，在使用该对象时，必须确保区限功能已启用，并使用 <code>using</code> 包裹上下文。</p>`,116)]))}const u=s(p,[["render",c]]),r=JSON.parse('{"path":"/posts/dotnet/aspnetcore-fundamentals-logging/","title":"ASP.NET Core 框架基础 - 日志系统","lang":"zh-CN","frontmatter":{"title":"ASP.NET Core 框架基础 - 日志系统","date":"2017-06-02T21:50:50.000Z","description":".NET Core 提供了独立的日志模型使我们可以采用统一的 API 来完成针对日志记录的编程，同时也可以利用其扩展点对这个模型进行定制","category":["ASP.NET Core"],"tag":["aspnet-core"]},"git":{"updatedTime":1772706409000,"contributors":[{"name":"Frost He","username":"","email":"frosthe@qq.com","commits":1}],"changelog":[{"hash":"ffa4807bd7d8fdbc3c457d61dcbe1be8e2744be4","time":1772706409000,"email":"frosthe@qq.com","author":"Frost He","message":"博客迁移初步完成"}]},"filePathRelative":"posts/dotnet/aspnetcore-fundamentals-logging/index.md","excerpt":"<p>参考资料:</p>\\n<ul>\\n<li><a href=\\"https://docs.microsoft.com/en-us/aspnet/core/fundamentals/logging/?view=aspnetcore-2.1&amp;tabs=aspnetcore2x\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">Logging in ASP.NET Core</a></li>\\n<li><a href=\\"https://docs.microsoft.com/en-us/aspnet/core/fundamentals/logging/loggermessage?view=aspnetcore-2.1\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">Logging with Logger Message</a></li>\\n<li><a href=\\"http://www.cnblogs.com/artech/p/logging-for-net-core-01.html\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\">.NET Core 的日志</a></li>\\n</ul>"}');export{u as comp,r as data};
